// Validar y preparar datos recibidos del webhook
const body = $input.item.json.body || $input.item.json;

// Validar que tenga los datos necesarios
if (!body.auditoria_id) {
  throw new Error('Falta auditoria_id en el request');
}

// Si viene con datos completos del sistema, usarlos
// Si solo viene auditoria_id, necesitaremos consultar la DB después
const data = {
  auditoria_id: body.auditoria_id,
  preparacion: body.preparacion || null,
  actividad: body.actividad || null,
  fechas: body.fechas || null,
  auditados: body.auditados || [],
  comunicaciones_ids: body.comunicaciones_ids || []
};

// Si faltan datos, marcar para consultar DB
const necesitaConsultaDB = !data.preparacion || !data.actividad || data.auditados.length === 0;

return [{
  json: {
    auditoria_id: data.auditoria_id,
    preparacion: data.preparacion,
    actividad: data.actividad,
    fechas: data.fechas,
    auditados: data.auditados,
    comunicaciones_ids: data.comunicaciones_ids,
    necesita_consulta_db: necesitaConsultaDB
  }
}];

// Parsear respuesta de DB si fue necesario consultarla
// O usar datos que ya venían del webhook
const inputData = $input.item.json;

let datosCompletos;

// Si se consultó DB, parsear la respuesta
if (inputData.resultado || inputData.auditoria) {
  const dbData = inputData.resultado || inputData;
  datosCompletos = {
    auditoria: dbData.auditoria,
    preparacion: dbData.preparacion,
    actividad: dbData.actividad,
    auditor_responsable: dbData.auditor_responsable,
    auditados: dbData.auditados || []
  };
} else {
  // Usar datos que ya venían del webhook
  // IMPORTANTE: Si los auditados no tienen email/nombre, necesitamos consultarlos
  // Por ahora, asumimos que vienen del webhook o se consultaron antes
  datosCompletos = {
    auditoria: {
      id: inputData.auditoria_id,
      fecha_inicio: inputData.fechas?.inicio,
      fecha_fin: inputData.fechas?.fin
    },
    preparacion: inputData.preparacion,
    actividad: inputData.actividad,
    auditor_responsable: inputData.auditor_responsable || null,
    auditados: inputData.auditados.map(a => ({
      user_id: a.user_id,
      email: a.email || null,
      nombre: a.nombre || null,
      comunicacion_id: a.comunicacion_id || null
    }))
  };

  // Si los auditados no tienen email/nombre, necesitamos consultar DB
  const auditadosSinEmail = datosCompletos.auditados.filter(a => !a.email || !a.nombre);
  if (auditadosSinEmail.length > 0 && !inputData.auditados_completos) {
    // Marcar que necesitamos consultar emails
    datosCompletos.necesita_emails = true;
  }
}

// Validar que tengamos datos mínimos
if (!datosCompletos.preparacion || !datosCompletos.actividad || datosCompletos.auditados.length === 0) {
  throw new Error('Faltan datos necesarios para enviar notificación');
}

// Asegurar que todos los auditados tengan email y nombre
// Si faltan, los obtenemos de la función SQL que ya los incluye
// O los consultamos aquí si es necesario

return [{
  json: datosCompletos
}];

// Duplicar datos generales en cada auditado antes del split
const item = $input.item.json;

// Validar que tengamos los datos necesarios
if (!item.auditados || !Array.isArray(item.auditados) || item.auditados.length === 0) {
  throw new Error('No hay auditados para procesar');
}

// Crear un item por cada auditado con todos los datos generales incluidos
// Cada item tendrá: auditado (individual) + datos generales
return item.auditados.map(auditado => ({
  json: {
    auditado: auditado,
    auditoria: item.auditoria,
    preparacion: item.preparacion,
    actividad: item.actividad,
    auditor_responsable: item.auditor_responsable || null
  }
}));

// Obtener datos del item actual (ya viene con todos los datos duplicados)
// Después del nodo 'Code - Duplicar Datos', cada item tiene:
// { auditado: {...}, auditoria: {...}, preparacion: {...}, actividad: {...} }
const item = $input.item.json;

// Extraer datos del item (todos están disponibles directamente)
const auditado = item.auditado;
const preparacion = item.preparacion;
const actividad = item.actividad;
const auditoria = item.auditoria;
const auditor = item.auditor_responsable || {};

// Formatear fecha de inicio
const fechaInicio = auditoria.fecha_inicio 
  ? new Date(auditoria.fecha_inicio).toLocaleDateString('es-ES', { 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    })
  : 'No definida';

// Calcular fecha límite para documentación (8 días hábiles desde hoy)
const hoy = new Date();
let diasAgregados = 0;
let diasHabiles = 0;

while (diasHabiles < 8) {
  diasAgregados++;
  const fecha = new Date(hoy);
  fecha.setDate(fecha.getDate() + diasAgregados);
  const diaSemana = fecha.getDay();
  // Excluir sábados (6) y domingos (0)
  if (diaSemana !== 0 && diaSemana !== 6) {
    diasHabiles++;
  }
}

const fechaLimiteDoc = new Date(hoy);
fechaLimiteDoc.setDate(fechaLimiteDoc.getDate() + diasAgregados);
const fechaLimiteFormateada = fechaLimiteDoc.toLocaleDateString('es-ES', {
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Generar HTML del correo
const htmlTemplate = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { 
      font-family: Arial, sans-serif; 
      line-height: 1.6; 
      color: #333; 
      background: #f3f4f6;
      margin: 0;
      padding: 0;
    }
    .container { 
      max-width: 600px; 
      margin: 0 auto; 
      padding: 20px; 
    }
    .header { 
      background: #2563eb; 
      color: white; 
      padding: 20px; 
      border-radius: 8px 8px 0 0; 
    }
    .header h1 {
      margin: 0 0 10px 0;
      font-size: 24px;
    }
    .content { 
      background: #f9fafb; 
      padding: 20px; 
      border-radius: 0 0 8px 8px; 
    }
    .section {
      background: white;
      padding: 15px;
      margin: 12px 0;
      border-left: 4px solid #2563eb;
      border-radius: 4px;
    }
    .section h3 {
      margin-top: 0;
      color: #2563eb;
    }
    .highlight-box {
      background: #eff6ff;
      border-left: 4px solid #2563eb;
      padding: 15px;
      margin: 15px 0;
      border-radius: 4px;
    }
    .footer { 
      text-align: center; 
      margin-top: 20px; 
      color: #6b7280; 
      font-size: 12px; 
    }
    .button {
      display: inline-block;
      background: #2563eb;
      color: white;
      padding: 12px 24px;
      text-decoration: none;
      border-radius: 4px;
      margin-top: 10px;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📋 Notificación de Auditoría</h1>
      <p>Actividad #${actividad.numero || 'N/A'}</p>
    </div>

    <div class="content">
      <p>Hola <strong>${auditado.nombre || 'Auditado'}</strong>,</p>

      <p>Te informamos que has sido designado como auditado para la siguiente auditoría:</p>

      <div class="section">
        <h3>📅 Fecha de Inicio</h3>
        <p><strong>${fechaInicio}</strong></p>
      </div>

      <div class="section">
        <h3>🎯 Objetivo</h3>
        <p>${(preparacion.objetivo || 'No especificado').replace(/\n/g, '<br>')}</p>
      </div>

      <div class="section">
        <h3>📊 Alcance</h3>
        <p>${(preparacion.alcance || 'No especificado').replace(/\n/g, '<br>')}</p>
      </div>

      ${preparacion.criterios ? `
      <div class="section">
        <h3>✅ Criterios</h3>
        <p>${preparacion.criterios.replace(/\n/g, '<br>')}</p>
      </div>
      ` : ''}

      ${preparacion.riesgos ? `
      <div class="section">
        <h3>⚠️ Riesgos</h3>
        <p>${preparacion.riesgos.replace(/\n/g, '<br>')}</p>
      </div>
      ` : ''}

      <div class="highlight-box">
        <h3 style="margin-top: 0;">📄 Solicitud de Documentación</h3>
        <p>
          Se solicita documentación relacionada a las áreas auditadas.
          <strong>El plazo de entrega es de 8 días hábiles.</strong>
        </p>
        <p><strong>Fecha límite: ${fechaLimiteFormateada}</strong></p>
        <p style="font-size: 12px; color: #6b7280; margin-top: 10px;">
          Recibirás una solicitud formal en el sistema con los detalles específicos de la documentación requerida.
        </p>
      </div>

      <p style="margin-top: 20px;">
        Por favor, revisa esta información en el sistema de auditoría y confirma tu participación.
      </p>

      ${actividad.descripcion ? `
      <div class="section">
        <h3>📋 Descripción de la Actividad</h3>
        <p>${actividad.descripcion.replace(/\n/g, '<br>')}</p>
      </div>
      ` : ''}
    </div>

    <div class="footer">
      <p>
        Este es un correo automático del Sistema de Auditoría.<br>
        Generado el ${new Date().toLocaleDateString('es-ES')} a las ${new Date().toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}<br>
        No responder a este mensaje.
      </p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    auditado_id: auditado.user_id,
    auditado_email: auditado.email,
    auditado_nombre: auditado.nombre,
    comunicacion_id: auditado.comunicacion_id,
    auditoria_id: auditoria.id,
    fecha_limite_documentacion: fechaLimiteDoc.toISOString().split('T')[0],
    html: htmlTemplate,
    asunto: `Auditoría - Actividad #${actividad.numero || 'N/A'} - Notificación de Inicio`
  }
}];
